parameters.jsCode:
const query = $('Parse AI JSON').first().json.original_text.toLowerCase();
const rows = $input.all().map(item => item.json);

const now = new Date();
const currentMonth = now.getMonth();
const currentYear = now.getFullYear();

function parseDate(value) {
  if (!value) return null;
  return new Date(value);
}

let filtered = rows;

if (query.includes('місяц') || query.includes('цього місяця')) {
  filtered = filtered.filter(row => {
    const d = parseDate(row.Date);
    return d && d.getMonth() === currentMonth && d.getFullYear() === currentYear;
  });
}

if (query.includes('тижд')) {
  const weekAgo = new Date();
  weekAgo.setDate(now.getDate() - 7);

  filtered = filtered.filter(row => {
    const d = parseDate(row.Date);
    return d && d >= weekAgo && d <= now;
  });
}

const totalExpense = filtered
  .filter(row => String(row.Type).toLowerCase() === 'expense')
  .reduce((sum, row) => sum + Number(row.Amount || 0), 0);

const totalIncome = filtered
  .filter(row => String(row.Type).toLowerCase() === 'income')
  .reduce((sum, row) => sum + Number(row.Amount || 0), 0);

const categoryTotals = {};

for (const row of filtered) {
  const category = row.Category || 'Other';
  const amount = Number(row.Amount || 0);

  if (!categoryTotals[category]) {
    categoryTotals[category] = 0;
  }

  categoryTotals[category] += amount;
}

return [
  {
    json: {
      query,
      totalExpense,
      totalIncome,
      balance: totalIncome - totalExpense,
      categoryTotals,
      transactions: filtered
    }
  }
];

const date = $json.date;
const time = $json.time;
const endTime = $json.end_time;

const start = new Date(`${date}T${time}:00+03:00`);
const end = new Date(`${date}T${endTime}:00+03:00`);

const bufferStart = new Date(start);
bufferStart.setMinutes(bufferStart.getMinutes() - 15);

const bufferEnd = new Date(end);
bufferEnd.setMinutes(bufferEnd.getMinutes() + 15);

return [{
  json: {
    ...$json,
    start_iso: start.toISOString(),
    end_iso: end.toISOString(),
    buffer_start_iso: bufferStart.toISOString(),
    buffer_end_iso: bufferEnd.toISOString()
  }
}];

const meeting = $('Build Meeting Time').first().json;

const events = $input.all().filter(e => {
  const hasId = !!e.json.id;
  const hasSummary = !!e.json.summary;
  const hasStart = !!(e.json.start?.dateTime || e.json.start?.date);

  return hasId || hasSummary || hasStart;
});

const hasConflict = events.length > 0;

return [{
  json: {
    ...meeting,
    has_conflict: hasConflict,
    conflicts_count: events.length,
    conflicts: events.map(e => ({
      title: e.json.summary || e.json.title || 'Без назви',
      start: e.json.start?.dateTime || e.json.start?.date || '',
      end: e.json.end?.dateTime || e.json.end?.date || ''
    }))
  }
}];

